#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

int cmp_ll(const void *a, const void *b) {
    int64_t x = *(int64_t *)a, y = *(int64_t *)b;
    if (x < y) return -1;
    if (x > y) return 1;
    return 0;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int64_t *def = (int64_t *)malloc(N * sizeof(int64_t));
        int defCnt = 0;
        for (int i = 0; i < N; ++i) {
            int64_t a; scanf("%lld", &a);
            if (a < 0) def[defCnt++] = -a;
        }
        int64_t X; scanf("%lld", &X);
        if (defCnt == 0) {
            printf("0\n");
            free(def);
            continue;
        }
        if (X >= defCnt) {
            int64_t sum = 0;
            for (int i = 0; i < defCnt; ++i) sum += def[i];
            printf("%lld\n", sum);
            free(def);
            continue;
        }
        qsort(def, defCnt, sizeof(int64_t), cmp_ll);
        int idx = defCnt - (int)X - 1; // (m - X)-th smallest (0‑based)
        int64_t k = def[idx];
        int64_t cost = k * X;
        for (int i = 0; i < defCnt; ++i) {
            if (def[i] > k) cost += def[i] - k;
        }
        printf("%lld\n", cost);
        free(def);
    }
    return 0;
}

