            long long a; cin>>a;
            if(a<0) deficits.push_back(-a);
        }
        long long X; cin>>X;
        long long m = deficits.size();
        if(m==0){
            cout<<0<<"\n";
            continue;
        }
        if(X>=m){
            long long sum=0; for(auto d:deficits) sum+=d;
            cout<<sum<<"\n";
            continue;
        }
        sort(deficits.begin(), deficits.end());
        long long k = deficits[m - X - 1]; // (m-X)-th smallest
        long long cost = k * X;
        for(auto d:deficits) if(d>k) cost += d - k;
        cout<<cost<<"\n";
    }
    return 0;
}

