import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            st = new StringTokenizer(br.readLine());
            List<Long> deficits = new ArrayList<>();
            for (int i = 0; i < N; i++) {
                long a = Long.parseLong(st.nextToken());
                if (a < 0) deficits.add(-a);
            }
            long X = Long.parseLong(br.readLine().trim());
            int m = deficits.size();
            if (m == 0) {
                out.append(0).append('\n');
                continue;
            }
            if (X >= m) {
                long sum = 0;
                for (long d : deficits) sum += d;
                out.append(sum).append('\n');
                continue;
            }
            Collections.sort(deficits);
            long k = deficits.get(m - (int)X - 1);
            long cost = k * X;
            for (long d : deficits) if (d > k) cost += d - k;
            out.append(cost).append('\n');
        }
        System.out.print(out.toString());
    }
}

