let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  let deficits = [];
  for (let i = 0; i < N; i++) {
    const a = Number(input[idx++]);
    if (a < 0) deficits.push(-a);
  }
  const X = Number(input[idx++]);
  const m = deficits.length;
  if (m === 0) {
    outputs.push('0');
    continue;
  }
  if (X >= m) {
    const sum = deficits.reduce((s, v) => s + v, 0);
    outputs.push(String(sum));
    continue;
  }
  deficits.sort((a, b) => a - b);
  const k = deficits[m - X - 1];
  let cost = k * X;
  for (const d of deficits) {
    if (d > k) cost += d - k;
  }
  outputs.push(String(cost));
}
